"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { createUserWithEmailAndPassword, signInWithEmailAndPassword } from "firebase/auth";
import { auth, db } from "@/firebase";
import { setDoc, doc } from "firebase/firestore";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { useRouter } from "next/navigation";
import { toast } from "sonner"; 

const formSchema = z.object({
  email: z.string().email("╨Т╨▓╨╡╨┤╨╕╤В╨╡ ╨║╨╛╤А╤А╨╡╨║╤В╨╜╤Л╨╣ email"),
  password: z.string().min(6, "╨Я╨░╤А╨╛╨╗╤М ╨┤╨╛╨╗╨╢╨╡╨╜ ╤Б╨╛╨┤╨╡╤А╨╢╨░╤В╤М ╨╝╨╕╨╜╨╕╨╝╤Г╨╝ 6 ╤Б╨╕╨╝╨▓╨╛╨╗╨╛╨▓"),
});

export function AuthForm({ type }: { type: "login" | "signup" }) {
  const [isLoading, setIsLoading] = useState(false);
  const router = useRouter();

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: { email: "", password: "" },
  });

  async function onSubmit(values: z.infer<typeof formSchema>) {
    setIsLoading(true);
    try {
      if (type === "signup") {
        const userCredential = await createUserWithEmailAndPassword(auth, values.email, values.password);
        const user = userCredential.user;

        await setDoc(doc(db, "users", user.uid), {
          email: user.email,
          createdAt: new Date().toISOString()
        });

        toast.success("╨а╨╡╨│╨╕╤Б╤В╤А╨░╤Ж╨╕╤П ╤Г╤Б╨┐╨╡╤И╨╜╨░!");
      } else {
        await signInWithEmailAndPassword(auth, values.email, values.password);
        toast.success("╨Т╤Е╨╛╨┤ ╤Г╤Б╨┐╨╡╤И╨╡╨╜!");
      }
      setTimeout(() => {
          router.push("/profile");
      }, 1000)
    } catch (error: any) {
      console.error(error);
      const errorCode = error.code;

      if (errorCode === 'auth/email-already-in-use') {
        toast.error("╨н╤В╨╛╤В email ╤Г╨╢╨╡ ╨╖╨░╤А╨╡╨│╨╕╤Б╤В╤А╨╕╤А╨╛╨▓╨░╨╜. ╨Я╨╛╨╢╨░╨╗╤Г╨╣╤Б╤В╨░, ╨▓╨╛╨╣╨┤╨╕╤В╨╡ ╨▓ ╨░╨║╨║╨░╤Г╨╜╤В.");
      } else if (errorCode === 'auth/invalid-credential' || errorCode === 'auth/wrong-password') {
        toast.error("╨Э╨╡╨▓╨╡╤А╨╜╤Л╨╣ email ╨╕╨╗╨╕ ╨┐╨░╤А╨╛╨╗╤М.");
      } else if (errorCode === 'auth/weak-password') {
        toast.error("╨Я╨░╤А╨╛╨╗╤М ╤Б╨╗╨╕╤И╨║╨╛╨╝ ╨┐╤А╨╛╤Б╤В╨╛╨╣. ╨Я╤А╨╕╨┤╤Г╨╝╨░╨╣╤В╨╡ ╨╝╨╕╨╜╨╕╨╝╤Г╨╝ 6 ╤Б╨╕╨╝╨▓╨╛╨╗╨╛╨▓.");
      } else if (errorCode === 'auth/too-many-requests') {
        toast.error("╨б╨╗╨╕╤И╨║╨╛╨╝ ╨╝╨╜╨╛╨│╨╛ ╨┐╨╛╨┐╤Л╤В╨╛╨║ ╨▓╤Е╨╛╨┤╨░. ╨Я╨╛╨┐╤А╨╛╨▒╤Г╨╣╤В╨╡ ╨┐╨╛╨╖╨╢╨╡.");
      } else {
        toast.error("╨Я╤А╨╛╨╕╨╖╨╛╤И╨╗╨░ ╨╛╤И╨╕╨▒╨║╨░. ╨Я╤А╨╛╨▓╨╡╤А╤М╤В╨╡ ╨┤╨░╨╜╨╜╤Л╨╡ ╨╕ ╨┐╨╛╨┐╤А╨╛╨▒╤Г╨╣╤В╨╡ ╤Б╨╜╨╛╨▓╨░.");
      }
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 w-full max-w-sm border border-border p-6 rounded-2xl bg-card shadow-xl">
        <h2 className="text-2xl font-bold font-space-grotesk text-center">
          {type === "login" ? "╨Т╤Е╨╛╨┤ ╨▓ ╨░╨║╨║╨░╤Г╨╜╤В" : "╨Э╨╛╨▓╤Л╨╣ ╨░╨║╨║╨░╤Г╨╜╤В"}
        </h2>
        <FormField
          control={form.control}
          name="email"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Email</FormLabel>
              <FormControl>
                <Input placeholder="name@example.com" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="password"
          render={({ field }) => (
            <FormItem>
              <FormLabel>╨Я╨░╤А╨╛╨╗╤М</FormLabel>
              <FormControl>
                <Input type="password" placeholder="******" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <Button type="submit" className="w-full font-bold" disabled={isLoading}>
          {isLoading ? "╨Ч╨░╨│╤А╤Г╨╖╨║╨░..." : type === "login" ? "╨Т╨╛╨╣╤В╨╕" : "╨Ч╨░╤А╨╡╨│╨╕╤Б╤В╤А╨╕╤А╨╛╨▓╨░╤В╤М╤Б╤П"}
        </Button>
      </form>
    </Form>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Sparkles, Loader2 } from "lucide-react";

interface IdeaFormProps {
  onGenerate: (theme: string) => Promise<void>;
  isLoading: boolean;
}

export function IdeaForm({ onGenerate, isLoading }: IdeaFormProps) {
  const [theme, setTheme] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!theme.trim()) return;
    await onGenerate(theme);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e as any);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-3xl mx-auto space-y-4">
      <div className="relative group">
        <Textarea
          placeholder="╨╜╨░╨┐╤А╨╕╨╝╨╡╤А, '╨Ш╨Ш ╨┤╨╗╤П ╤Б╨░╨┤╨╛╨▓╨╛╨┤╤Б╤В╨▓╨░', '╨╝╨╛╨▒╨╕╨╗╤М╨╜╨░╤П ╨╕╨│╤А╨░ ╤Б ╨║╨╛╤В╨░╨╝╨╕'..."
          value={theme}
          onChange={(e) => setTheme(e.target.value)}
          onKeyDown={handleKeyDown}
          className="min-h-[140px] text-lg p-6 pr-16 shadow-2xl bg-card border-2 border-primary/20 focus-visible:ring-2 focus-visible:ring-primary focus-visible:border-primary transition-all rounded-3xl resize-none"
          disabled={isLoading}
        />
        <Button 
          type="submit" 
          size="icon"
          className="absolute bottom-5 right-5 h-12 w-12 rounded-full transition-transform hover:scale-105 shadow-md shadow-primary/20"
          disabled={isLoading || !theme.trim()}
        >
          {isLoading ? (
            <Loader2 className="h-6 w-6 animate-spin" />
          ) : (
             <Sparkles className="h-6 w-6" />
          )}
        </Button>
      </div>
    </form>
  );
}
